scwin.f_ChkKeyCode = function(dataListObj, rowIndex, colID, value) {
    let result = "";

    for (var i = 0; i < value.length; i++) {
        var code = value.charCodeAt(i);
        if (
            (code >= 33 && code <= 39) || // ! " # $ % & '
            (code >= 91 && code <= 96) || // [ \ ] ^ _ `
            (code >= 123 && code <= 126) || // { | } ~
            code == 63 || // ?
            code == 64 || // @
            code == 43 || // +
            code == 59 || // ;
            code == 0    // 널문자
        ) {
            // 특수문자: 아무것도 하지 않음(제거)
        } else {
            result += value.charAt(i);
        }
    }

    dataListObj.setCellData(rowIndex, colID, result);
};

